def _quantize_to_error_threshold(
    self, colors, method, kmeans, dither, threshold, sort_palette=SORT_NONE
):
    """
    Quantizes the image using as few colors as possible (up to
    ``colors``) such that the mean square error between the original
    image and the quantized image is at or below ``threshold``.
    """
    from . import ImageChops, ImageStat

    original_rgb = self.convert("RGB")

    def mean_square_error(im):
        diff = ImageChops.difference(original_rgb, im.convert("RGB"))
        stat = ImageStat.Stat(diff)
        return sum(rms**2 for rms in stat.rms) / len(stat.rms)

    color_count = 2
    while True:
        color_count = min(color_count, colors)
        candidate = self.quantize(
            color_count, method, kmeans, dither=dither, sort_palette=sort_palette
        )
        if color_count >= colors or mean_square_error(candidate) <= threshold:
            return candidate
        color_count *= 2

